insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:1-2-8-compression:tf:be04309b', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Lossy compression can always be reversed to restore the exact original file."}'::jsonb, '{"answer": false, "explain": "Lossy compression permanently removes some data — decompressing gives a close copy, not an exact one. Only lossless compression guarantees exact restoration."}'::jsonb),
('computer-science:1-2-8-compression:tf:c3d25151', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Lossless compression removes no data, so the original file can be reconstructed exactly."}'::jsonb, '{"answer": true, "explain": "Correct — that is the defining feature of lossless compression."}'::jsonb),
('computer-science:1-2-8-compression:tf:a240ff01', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Lossless compression is generally suited to text documents, spreadsheets and program code."}'::jsonb, '{"answer": true, "explain": "Correct — these are files where every bit matters, so nothing can be safely discarded."}'::jsonb),
('computer-science:1-2-8-compression:tf:a094f3d6', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Lossy compression is generally suited to images, audio and video, where minor quality loss often goes unnoticed."}'::jsonb, '{"answer": true, "explain": "Correct — a small, targeted loss of detail in these file types is often imperceptible to most people."}'::jsonb),
('computer-science:1-2-8-compression:tf:2217e5a6', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Lossless compression usually reduces file size by more than lossy compression does on the same file."}'::jsonb, '{"answer": false, "explain": "The opposite is generally true: lossy compression usually achieves a much bigger size reduction, because it permanently discards data rather than keeping everything."}'::jsonb),
('computer-science:1-2-8-compression:tf:2fff5b94', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Bandwidth is the maximum amount of data a network connection can carry in a given time."}'::jsonb, '{"answer": true, "explain": "Correct — and compressed files use less of that available bandwidth."}'::jsonb),
('computer-science:1-2-8-compression:tf:b3aab11e', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "JPEG and ZIP are both examples of lossless compression formats."}'::jsonb, '{"answer": false, "explain": "JPEG is a lossy format (used for photos); ZIP is a lossless format (used for documents and program files) — they are not the same type."}'::jsonb),
('computer-science:1-2-8-compression:learn:d83ae6da', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "Why do computer files need to be compressed?", "reading": "<h4>The three real-world pressures behind compression</h4>\n<ul>\n<li>A <strong>compressed</strong> file has been processed so that it takes up <strong>less storage space</strong> than the original, uncompressed file.</li>\n<li>Smaller files mean more of them fit on a limited storage device — a phone, a memory card, a company''s servers — without having to buy extra storage.</li>\n<li>Smaller files also <strong>transfer faster</strong>: they take less time to upload to a website, download onto a device, or send as an email attachment.</li>\n<li>Every network connection has a maximum <strong>bandwidth</strong> — the amount of data it can carry in a given time. Compressed files use less of that bandwidth, which matters when many people share the same connection (e.g. a school Wi-Fi network) or when a connection is slow.</li>\n<li><strong>Streaming</strong> video or music depends on compression: an uncompressed film would be far too large to send fast enough to play smoothly as it arrives, so it has to be compressed first.</li>\n</ul>\n<h4>The trade-off compression always involves</h4>\n<ul>\n<li>Compression is not free — reducing a file''s size always means changing HOW the data is stored, and, for one of the two methods you need to know, can mean losing some of the original data permanently.</li>\n<li>This is exactly why there are two different approaches, <strong>lossy</strong> and <strong>lossless</strong>, and why choosing the right one for a given file is itself an exam skill.</li>\n</ul>", "question": "A company wants to publish its training videos on its website. Which of these is a genuine reason to compress the video files first?", "options": ["It stops the videos from being copied or downloaded by any visitor to the site", "It reduces the video files'' size, so less server storage is used and streaming is faster", "It automatically improves the resolution and colour quality of every video without recompressing it", "It converts the videos into a file type that only the company''s own website is able to open"]}'::jsonb, '{"answer": 1, "explain": "Smaller video files need less server storage, transfer more quickly, and use less of the network''s limited bandwidth — the three real reasons files are compressed."}'::jsonb),
('computer-science:1-2-8-compression:learn:0d6445d9', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "What is lossy compression?", "reading": "<h4>The definition</h4>\n<ul>\n<li><strong>Lossy compression</strong> permanently removes some of a file''s data during compression. It targets detail that people are <strong>less likely to notice</strong> — for example, very subtle colour differences in an image, or extremely high or low sound frequencies in an audio file.</li>\n<li>Because data is genuinely thrown away, the file <strong>cannot be restored to its exact original state</strong> once it has been compressed — decompressing it gives a close copy, not an identical one.</li>\n</ul>\n<h4>What lossy compression is good at</h4>\n<ul>\n<li>It produces a <strong>much smaller file size</strong> than lossless compression can usually achieve on the same content, because it isn''t forced to keep every bit.</li>\n<li>The trade-off is a <strong>reduction in quality</strong> — but for the file types it''s normally used on, that reduction is small enough that most people never notice it.</li>\n</ul>\n<h4>Where it is normally used</h4>\n<ul>\n<li>Lossy compression suits <strong>images, audio and video</strong> — files where a small, targeted loss of detail is very unlikely to be noticed, but a big drop in file size is extremely valuable (streaming, uploading photos, downloading music).</li>\n<li>It is not suitable for files where every bit matters, such as text documents or program code — that''s covered on the next card.</li>\n</ul>", "question": "Why can a file compressed with lossy compression never be restored to its exact original state?", "options": ["Because lossy compression always encrypts the file with a password", "Because some of the original data was permanently removed and cannot be recovered", "Because lossy compression can only ever be applied to files that were never saved correctly", "Because the file format automatically changes every time it is opened"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression deletes some data as part of shrinking the file. That data is gone for good, so decompressing produces a close approximation, not the exact original."}'::jsonb),
('computer-science:1-2-8-compression:learn:24af51d7', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "What is lossless compression?", "reading": "<h4>The definition</h4>\n<ul>\n<li><strong>Lossless compression</strong> removes no data at all. Instead, it stores the same information in a more efficient way, so the file still shrinks — but nothing is thrown away.</li>\n<li>Because no data is lost, the original file can be <strong>reconstructed exactly</strong>, bit for bit, when it is decompressed.</li>\n</ul>\n<h4>What lossless compression is good at</h4>\n<ul>\n<li>It guarantees the decompressed file is <strong>identical</strong> to the file before it was compressed — every character, formula, pixel or instruction is preserved.</li>\n<li>The trade-off is that it usually achieves a <strong>smaller reduction</strong> in file size than lossy compression manages on the same content, since it isn''t allowed to discard anything.</li>\n</ul>\n<h4>Where it is normally used</h4>\n<ul>\n<li>Lossless compression is required for files where <strong>every bit matters</strong>: text documents, spreadsheets, program code, and some images where exact detail is essential (e.g. a company logo or a diagram with fine lines).</li>\n<li>If a spreadsheet''s formulas or a program''s code were compressed using a lossy method, even one permanently altered character could break the formula or stop the program running — which is why lossless is the only safe choice for these file types.</li>\n</ul>", "question": "A company''s source code for its main product must be compressed before being backed up. Why must lossless compression be used rather than lossy?", "options": ["Because lossless compression always produces a much smaller file size than lossy compression ever manages", "Because source code files are too large for lossy compression to work on", "Because even one permanently altered character could break the code, so nothing can be safely discarded", "Because lossy compression can only be applied to image and audio files"]}'::jsonb, '{"answer": 2, "explain": "Program code needs every character to be exact. Lossless compression guarantees the decompressed code is identical to the original, whereas lossy compression could permanently corrupt it."}'::jsonb),
('computer-science:1-2-8-compression:learn:e91de4ca', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "Lossy vs lossless: the real difference", "reading": "<h4>Side by side</h4>\n<table>\n<tr><th>Factor</th><th>Lossy compression</th><th>Lossless compression</th></tr>\n<tr><td>Data removed?</td><td>Yes — permanently</td><td>No — none at all</td></tr>\n<tr><td>Can the original be restored exactly?</td><td>No — only a close approximation</td><td>Yes — exactly, bit for bit</td></tr>\n<tr><td>Typical size reduction</td><td>Much larger reduction</td><td>Smaller reduction</td></tr>\n<tr><td>Best suited to</td><td>Images, audio, video</td><td>Text, spreadsheets, program code, some images</td></tr>\n</table>\n<h4>The trap examiners set</h4>\n<ul>\n<li>Students often describe the difference by WHERE each type is used (\"lossy is for pictures, lossless is for documents\") instead of describing the actual mechanism — WHAT happens to the data itself. A full-marks \"explain the difference\" answer must state that one method removes data permanently and the other does not, before (or as well as) giving an example.</li>\n<li>Neither type is simply \"better\" than the other. Lossy compression is not a worse or broken version of lossless — it is the right tool when a smaller file matters more than keeping every bit, and lossless is the right tool when accuracy matters more than file size.</li>\n</ul>", "question": "Which sentence correctly explains the difference between lossy and lossless compression, rather than just naming where each is used?", "options": ["Lossy compression is for photos and music; lossless compression is for documents and code", "Lossy compression permanently removes data so it can''t be restored exactly; lossless removes none, so it can", "Lossy compression is simply an older and worse technique that lossless compression has now completely replaced everywhere", "Lossy compression makes files bigger, while lossless compression makes files smaller"]}'::jsonb, '{"answer": 1, "explain": "A full explanation describes the mechanism — whether data is permanently removed or not — not just a list of example file types."}'::jsonb),
('computer-science:1-2-8-compression:learn:5ef9bf39', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "Choosing and justifying lossy or lossless for a scenario", "reading": "<h4>The two questions to ask</h4>\n<ul>\n<li><strong>1. Does every bit of this file matter?</strong> If losing even a small amount of detail would make the file wrong, broken or unusable (text, spreadsheets, code, some images), lossless is required.</li>\n<li><strong>2. Would a small, unnoticeable loss of detail be an acceptable trade-off for a much smaller, faster-moving file?</strong> If so (typical images, audio, video, especially for streaming or upload/download), lossy is usually the better choice.</li>\n</ul>\n<h4>How to structure a \"choose and justify\" answer</h4>\n<ul>\n<li><strong>Commit to ONE type first</strong> — lossy OR lossless, stated clearly. Do not hedge by describing both types and refusing to pick.</li>\n<li><strong>Then give reasons that only make sense for that chosen type</strong>, linked to the specific scenario in the question (storage limits, network speed, how critical exact accuracy is).</li>\n<li>A reason that actually supports the OTHER type earns nothing, even if it''s a true statement — justification marks are awarded only when the reason matches the choice.</li>\n</ul>\n<h4>Worked example</h4>\n<table>\n<tr><th>Scenario detail</th><th>What it tells you</th></tr>\n<tr><td>\"Users expect a song to start playing within a couple of seconds\"</td><td>Points to lossy — a much smaller file streams and starts playing faster</td></tr>\n<tr><td>\"The documents must remain word-for-word readable forever\"</td><td>Points to lossless — no detail can ever be permanently lost</td></tr>\n</table>", "question": "A justify-your-choice answer states: ''Lossy compression, because it never loses any of the original data.'' Why does this earn no justification marks?", "options": ["Because lossy compression justification questions are never actually worth any marks on this topic at all", "Because the reason given actually describes lossless compression, not the lossy choice that was made", "Because the answer is too short to be marked at all", "Because only lossless compression can ever be justified in an exam answer"]}'::jsonb, '{"answer": 1, "explain": "The stated reason contradicts the chosen type — ''never loses any data'' describes lossless compression, so it cannot support a lossy choice and earns nothing."}'::jsonb),
('computer-science:1-2-8-compression:learn:e5bea7dc', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'learn', 'mcq', 1, '{"readingTitle": "Compression in the real world", "reading": "<h4>Formats you may see named in a question</h4>\n<ul>\n<li><strong>JPEG</strong> — a widely used <strong>lossy</strong> format for photographs, where a small loss of detail keeps file sizes manageable for cameras, phones and websites.</li>\n<li><strong>MP3</strong> — a widely used <strong>lossy</strong> format for music and audio, removing sound detail that is largely inaudible to most listeners.</li>\n<li><strong>PNG</strong> — a <strong>lossless</strong> image format, often chosen for logos, screenshots and diagrams where sharp, exact edges and colours must be kept.</li>\n<li><strong>ZIP</strong> — a <strong>lossless</strong> format for bundling and shrinking any file type, commonly used for documents, program files and email attachments where nothing can be safely discarded.</li>\n</ul>\n<h4>What the exam does and does not expect</h4>\n<ul>\n<li>You are expected to know that lossy and lossless compression exist, understand what each one does to the data, and be able to choose and justify one for a scenario.</li>\n<li>You are <strong>not</strong> expected to know the internal algorithm any of these formats actually use, or to perform a compression calculation by hand — the specification for this topic is conceptual, not calculation-based.</li>\n</ul>", "question": "Which pair correctly matches a real-world file format to the type of compression it is known for?", "options": ["ZIP uses lossy compression, and JPEG uses lossless compression", "MP3 uses lossless compression, and PNG uses lossy compression", "JPEG uses lossy compression, and PNG uses lossless compression", "ZIP and MP3 both use exactly the same lossy compression method"]}'::jsonb, '{"answer": 2, "explain": "JPEG (photos) and MP3 (audio) are well-known lossy formats; PNG (images needing exact detail) and ZIP (general files) are well-known lossless formats."}'::jsonb),
('computer-science:1-2-8-compression:misc:d5f7f6da', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing lossy compression removes data completely at random, like deleting random parts of a file.</p><p><strong>✅ The correct idea:</strong> It targets <strong>specific</strong> detail that people are least likely to notice — for example, very high or low sound frequencies, or subtle colour differences in an image. It is a deliberate, targeted reduction, not random deletion.</p>", "question": "How does lossy compression decide which data to remove from a file?", "options": ["It removes data completely at random, picking bits and bytes with no pattern anywhere across the whole file", "It targets specific detail that people are unlikely to notice, such as subtle colour or sound differences", "It removes the first half of the file and keeps the second half unchanged", "It asks the user to manually select exactly which parts of the file to delete"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression targets detail that is least likely to be noticed, rather than deleting data randomly."}'::jsonb),
('computer-science:1-2-8-compression:misc:ccda77e9', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing lossless compression achieves a smaller file size than lossy compression on the same file.</p><p><strong>✅ The correct idea:</strong> The opposite is usually true. Lossless compression keeps every original bit of data, so it typically produces a <strong>bigger</strong> file than lossy compression on the same content, which permanently throws detail away to get much smaller.</p>", "question": "On the same original file, which type of compression usually produces the smaller result?", "options": ["Lossless compression, because it is the more advanced of the two methods", "Lossy compression, because it permanently discards some data rather than keeping everything", "They always produce exactly the same file size, whichever method is used", "Neither — the resulting file size depends only on the file''s original format, not the method used"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression usually achieves a much bigger reduction, since it is allowed to permanently discard data that lossless compression must keep."}'::jsonb),
('computer-science:1-2-8-compression:misc:ba8221d6', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing a file compressed with lossy compression can always be restored to its exact original state by decompressing it.</p><p><strong>✅ The correct idea:</strong> It cannot. Data removed during lossy compression is gone permanently — decompressing produces a copy that is close to, but <strong>not identical</strong> to, the true original. Only lossless compression guarantees an exact restoration.</p>", "question": "A photo is compressed using lossy compression, then later decompressed. What is true of the result?", "options": ["It is guaranteed to be pixel-for-pixel identical to the original photo", "It is a close copy of the original, but some detail has been permanently lost", "It becomes a completely different photo altogether, entirely unrelated to the original", "It is always restored to a higher quality than the original photo"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression permanently discards some data, so decompressing it can never produce an exact match of the original file."}'::jsonb),
('computer-science:1-2-8-compression:misc:455e53e5', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing any file type can safely use lossy compression, as long as the resulting file is smaller.</p><p><strong>✅ The correct idea:</strong> Files where every bit matters — text documents, spreadsheets, program code — must use <strong>lossless</strong> compression, since lossy compression could permanently corrupt characters, formulas or code and make the file unusable.</p>", "question": "Why is it unsafe to compress a spreadsheet of financial data using lossy compression?", "options": ["Because spreadsheets are always too large for any compression method to work on", "Because a permanently altered number or formula could make the figures wrong", "Because lossy compression only works on files stored on the internet", "Because spreadsheets automatically reject any attempt to compress them"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression can permanently change data. In a spreadsheet, that could silently corrupt a number or formula, so lossless compression must be used instead."}'::jsonb),
('computer-science:1-2-8-compression:misc:b8786f8c', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing compression is only really about saving storage space.</p><p><strong>✅ The correct idea:</strong> It is just as much about <strong>transfer</strong> — smaller files upload and download faster and use less of a network''s limited bandwidth, which is essential for streaming video or audio smoothly.</p>", "question": "Besides saving storage space, what is another genuine reason files are compressed?", "options": ["Compression makes a file completely impossible for anyone else to ever open or copy", "Smaller files transfer faster and use less of a network''s limited bandwidth", "Compression automatically fixes any errors that exist inside the file", "Compression permanently increases the resolution of an image file"]}'::jsonb, '{"answer": 1, "explain": "Faster transfer and reduced bandwidth use are just as important a reason for compression as saving storage space."}'::jsonb),
('computer-science:1-2-8-compression:misc:6aeb0c94', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that because lossy compression reduces file size by more, it is always the better choice.</p><p><strong>✅ The correct idea:</strong> The ''better'' choice depends entirely on whether losing some data permanently is acceptable for that file and its purpose — a bigger size reduction is worthless if the file becomes unusable, such as corrupted program code.</p>", "question": "Why is lossy compression not automatically the ''better'' choice, even though it usually shrinks a file by more?", "options": ["Because lossy compression always takes noticeably longer to perform than lossless compression does", "Because permanently losing data can make some files (e.g. program code) unusable, even if smaller", "Because lossy compression can only ever be applied to text files", "Because lossy compression always costs money to use, unlike lossless compression"]}'::jsonb, '{"answer": 1, "explain": "A bigger size reduction is only useful if the permanent data loss doesn''t matter for that file''s purpose — for code or exact records, it does matter, so lossless is required instead."}'::jsonb),
('computer-science:1-2-8-compression:tips:3ce8318d', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tips', 'mcq', 1, '{"readingTitle": "explain — The 1–2 mark ''state/define'' ladder", "reading": "<p>A typical question: <em>\"Define lossless compression.\"</em> [2 marks] Here is the same idea answered at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"It makes the file smaller.\"</p>\n<ul>\n<li>This is true of compression in general, but it doesn''t describe LOSSLESS compression specifically — it would also be true of lossy compression, so it can''t be credited as a definition of this particular method.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"It doesn''t lose any of the data.\"</p>\n<ul>\n<li>A genuinely correct point, but \"define\" needs the CONSEQUENCE too — what does not losing any data actually let you do? Without that second half, only one of the two marks is available.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"No data is removed during compression <strong>(1)</strong>, so the original file can be reconstructed/decompressed back to exactly what it was before <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters:</strong> \"State/define\" answers on this topic need to name what happens to the data AND the consequence that follows from it — a one-line vague answer like \"makes it smaller\" applies to compression in general, not to the specific method being asked about.</p>", "question": "A student answers ''Lossless compression: it keeps the file''s quality the same'' for a 2-mark ''define lossless compression'' question. What is this likely to score?", "options": ["2 marks, because quality staying the same is a correct and complete definition", "0 marks, because the answer given is entirely unrelated to the topic of compression itself", "Partial marks at best — it hints at the idea but doesn''t clearly state that no data is removed", "Full marks, because any true statement made about lossless compression always scores the maximum"]}'::jsonb, '{"answer": 2, "explain": "The answer gestures at the right idea but doesn''t clearly state the two creditable points — no data removed, and exact reconstruction — so it is unlikely to reach full marks."}'::jsonb),
('computer-science:1-2-8-compression:tips:b28be745', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tips', 'mcq', 1, '{"readingTitle": "explain — The 2-mark ''explain the difference'' ladder", "reading": "<p>A typical question: <em>\"Explain the difference between lossy and lossless compression.\"</em> [2 marks]</p>\n\n<p><strong>❌ 0 marks:</strong> \"Lossy is for pictures and lossless is for documents.\"</p>\n<ul>\n<li>This states WHERE each type is used, not WHAT the actual difference in the compression process is — it could be true and still miss the mechanism the question is asking about.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"Lossy loses some data but lossless doesn''t.\"</p>\n<ul>\n<li>A genuinely correct point, but \"explain the difference\" wants BOTH sides properly described, and this only develops the lossy half of the comparison.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"Lossy compression permanently removes some data so the file cannot be restored exactly <strong>(1)</strong>; lossless compression removes no data at all, so the file can be restored to exactly what it was before <strong>(1)</strong>.\"</p>\n\n<p><strong>The pattern:</strong> a 2-mark \"difference\" question on this topic almost always splits into one mark for each side of the comparison — write about lossy AND lossless, not just one of them.</p>", "question": "A 2-mark ''explain the difference'' question is answered with only ''Lossy compression removes some data permanently.'' What is the most likely outcome?", "options": ["Full marks, since the statement given is completely accurate", "Only 1 of the 2 marks, since the lossless side of the comparison is missing entirely", "0 marks, since the statement given doesn''t mention file size or bandwidth anywhere at all", "Full marks, since only one correct fact is needed to explain any difference"]}'::jsonb, '{"answer": 1, "explain": "A difference question needs both sides described. A correct statement about only lossy compression can earn at most half the marks."}'::jsonb),
('computer-science:1-2-8-compression:tips:df9a45ed', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tips', 'mcq', 1, '{"readingTitle": "tip — The ''choose + justify'' ladder (3–4 marks): commit to ONE type", "reading": "<p>\"Justify a choice\" questions on this topic always need TWO things in the right order: a committed choice (lossy OR lossless), then reasons that genuinely apply to THAT choice in THIS scenario.</p>\n\n<p><strong>❌ 0–1 marks:</strong> \"Lossy compression is smaller but loses quality, and lossless keeps everything but is bigger, so it depends.\"</p>\n<ul>\n<li>This hedges between both types instead of committing to one, so the justification marks can''t be credited against a clear choice.</li>\n</ul>\n\n<p><strong>⚠️ Partial marks:</strong> \"Lossless, because it doesn''t lose any data.\"</p>\n<ul>\n<li>A valid, committed choice — but only ONE justification point is given where the question wants more, developed and linked to the scenario.</li>\n</ul>\n\n<p><strong>✅ Full marks:</strong> \"Lossless compression, because it removes no data <strong>(1)</strong>, so the archived legal documents can always be reconstructed exactly, with every word intact even after years of storage <strong>(1)</strong>, and no detail can be permanently altered, which matters for an official record <strong>(1)</strong>.\"</p>\n\n<p>Two rules that catch real candidates out: commit to ONE type first, not a brand or a vague \"it depends\" — and make sure every justification point clearly matches the type you chose. A reason that only applies to the OTHER type earns nothing, even if it''s a true statement.</p>", "question": "You justify ''lossy compression'' using ''it removes no data, so nothing is ever lost.'' Why does this earn no justification marks?", "options": ["Because lossy compression justification questions on this specific topic are never worth any marks whatsoever at all", "Because the reason given actually describes lossless compression, contradicting the lossy choice that was made", "Because the answer is too short to be marked, regardless of what it says", "Because only lossless compression can ever be justified correctly in an exam answer"]}'::jsonb, '{"answer": 1, "explain": "The stated reason contradicts the chosen type — ''removes no data'' describes lossless compression, so it cannot support a lossy choice and earns nothing."}'::jsonb),
