('computer-science:1-3-1-networks-and-topologies:match:a9a01c82', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “LAN”?", "options": ["Requests and makes use of the services or resources a server provides", "Connects one network to a different network, such as a LAN to the Internet", "A network confined to a single site, such as one building or a small group of nearby buildings", "Provides shared services or resources that client computers request and use"]}'::jsonb, '{"answer": 2, "explain": "“LAN” means: A network confined to a single site, such as one building or a small group of nearby buildings"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:5ba36310', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “WAN”?", "options": ["A network confined to a single site, such as one building or a small group of nearby buildings", "A network spanning a large geographical area, such as multiple cities or countries", "The delay between data being sent and it arriving at its destination", "Storing data or running services on remote servers accessed over the Internet, rather than locally"]}'::jsonb, '{"answer": 1, "explain": "“WAN” means: A network spanning a large geographical area, such as multiple cities or countries"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:dd4e5216', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Bandwidth”?", "options": ["The maximum amount of data that can be transferred across a connection in a given time", "A network confined to a single site, such as one building or a small group of nearby buildings", "Hardware, built into or fitted inside a device, that lets it physically connect to a network", "Electrical or physical disruption (walls, other devices) that weakens or corrupts a signal"]}'::jsonb, '{"answer": 0, "explain": "“Bandwidth” means: The maximum amount of data that can be transferred across a connection in a given time"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:2bf65d35', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Latency”?", "options": ["The delay between data being sent and it arriving at its destination", "Lets wireless devices join a wired LAN by converting between wired and wireless signals", "A network spanning a large geographical area, such as multiple cities or countries", "Electrical or physical disruption (walls, other devices) that weakens or corrupts a signal"]}'::jsonb, '{"answer": 0, "explain": "“Latency” means: The delay between data being sent and it arriving at its destination"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:b6b02e20', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Interference”?", "options": ["The system of servers that converts a URL into the matching IP address", "A network spanning a large geographical area, such as multiple cities or countries", "Provides shared services or resources that client computers request and use", "Electrical or physical disruption (walls, other devices) that weakens or corrupts a signal"]}'::jsonb, '{"answer": 3, "explain": "“Interference” means: Electrical or physical disruption (walls, other devices) that weakens or corrupts a signal"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:a49af3c2', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Client (role)”?", "options": ["The system of servers that converts a URL into the matching IP address", "Hardware, built into or fitted inside a device, that lets it physically connect to a network", "The delay between data being sent and it arriving at its destination", "Requests and makes use of the services or resources a server provides"]}'::jsonb, '{"answer": 3, "explain": "“Client (role)” means: Requests and makes use of the services or resources a server provides"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:a103a871', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Server (role)”?", "options": ["Electrical or physical disruption (walls, other devices) that weakens or corrupts a signal", "Lets wireless devices join a wired LAN by converting between wired and wireless signals", "Provides shared services or resources that client computers request and use", "Requests and makes use of the services or resources a server provides"]}'::jsonb, '{"answer": 2, "explain": "“Server (role)” means: Provides shared services or resources that client computers request and use"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:686af54b', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Peer-to-peer network”?", "options": ["Every computer has equal status and can act as both client and server, with no dedicated central machine", "Requests and makes use of the services or resources a server provides", "Provides shared services or resources that client computers request and use", "Connects multiple wired devices within the same LAN, forwarding data to the addressed device only"]}'::jsonb, '{"answer": 0, "explain": "“Peer-to-peer network” means: Every computer has equal status and can act as both client and server, with no dedicated central machine"}'::jsonb),
('computer-science:1-3-1-networks-and-topologies:match:0265f421', 'computer-science', 'computer-science:1-3-1-networks-and-topologies', '1.3.1 Networks and Topologies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “NIC”?", "options": ["The delay between data being sent and it arriving at its destination", "Hardware, built into or fitted inside a device, that lets it physically connect to a network", "A network spanning a large geographical area, such as multiple cities or countries", "Connects multiple wired devices within the same LAN, forwarding data to the addressed device only"]}'::jsonb, '{"answer": 1, "explain": "“NIC” means: Hardware, built into or fitted inside a device, that lets it physically connect to a network"}'::jsonb)
